#include <stdio.h>

int main() {
    int numbers[] = {10, 25, 3, 47, 8};
    int size = sizeof(numbers) / sizeof(numbers[0]);

    printf("Dizi uzunlugu: %d\n", size);

    printf("Elemanlar: ");
    for (int i = 0; i < size; i++) {
        printf("%d ", numbers[i]);
    }
    printf("\n");

    // Toplam ve ortalama
    int sum = 0;
    for (int i = 0; i < size; i++) {
        sum += numbers[i];
    }
    double avg = (double)sum / size;

    printf("\nToplam: %d\n", sum);
    printf("Ortalama: %.2f\n", avg);

    // 2 boyutlu dizi (matris)
    int matrix[2][3] = {{1, 2, 3}, {4, 5, 6}};

    printf("\nMatris:\n");
    for (int i = 0; i < 2; i++) {
        for (int j = 0; j < 3; j++) {
            printf("%d ", matrix[i][j]);
        }
        printf("\n");
    }

    return 0;
}
